class Solution {
public:
    bool canMakeSubsequence(string str1, string str2) {
        int n = str1.size(), m = str2.size();
        int last[26] = {0};
        for (int i = 0; i < m; i++) {
            last[str2[i] - 'a'] = i;
        }
        int prev = -1;
        for (int i = 0; i < n; i++) {
            if (str1[i] != str2[prev + 1]) {
                if (last[str1[i] - 'a'] != 0 && last[str1[i] - 'a'] != prev + 1) {
                    prev = last[str1[i] - 'a'];
                } else {
                    return false;
                }
            } else {
                prev++;
            }
            if (prev == m - 1) {
                return true;
            }
        }
        return false;
    }
};
```

